DELIMITER $$
CREATE TRIGGER `trg_check_no_lambung` BEFORE UPDATE ON `dummy_data_dc_new` FOR EACH ROW BEGIN
    -- GUHI MAS → harus G
    IF NEW.NM_KAPAL LIKE '%GUHI MAS%' AND NEW.No_Lambung NOT REGEXP '^G[0-9]+$' THEN
        SIGNAL SQLSTATE '45000'
        SET MESSAGE_TEXT = 'No_Lambung untuk GUHI MAS harus diawali G';
    END IF;

    -- TANTO → harus T
    IF NEW.NM_KAPAL LIKE '%TANTO%' AND NEW.No_Lambung NOT REGEXP '^T[0-9]+$' THEN
        SIGNAL SQLSTATE '45000'
        SET MESSAGE_TEXT = 'No_Lambung untuk TANTO harus diawali T';
    END IF;

    -- MERATUS → harus M
    IF NEW.NM_KAPAL LIKE '%MERATUS%' AND NEW.No_Lambung NOT REGEXP '^M[0-9]+$' THEN
        SIGNAL SQLSTATE '45000'
        SET MESSAGE_TEXT = 'No_Lambung untuk MERATUS harus diawali M';
    END IF;

END
$$
DELIMITER ;

